from __future__ import annotations

import json


def serialize_record(record, format: str, schema_version=None):
    data = dict(record)
    if schema_version is not None:
        data = {'schema_version': schema_version, **data}
    if format == 'json':
        return json.dumps(data, sort_keys=True)
    if format == 'csv':
        fields = list(data.keys())
        return ','.join(fields) + '\n' + ','.join(str(data[field]) for field in fields)
    if format == 'toml':
        return '\n'.join(f'{key} = {json.dumps(value) if isinstance(value, str) else value}' for key, value in data.items())
    raise ValueError('unsupported format')

